// Compliant: Remove unnecessary conditionals
func processData(data []byte) {
    fmt.Println("Processing data")
    transformData(data)

    // If debugging is needed, use build tags or environment variables
    if isDebugMode() {
        log.Printf("Debug: data length = %d", len(data))
    }
}

func isDebugMode() bool {
    return os.Getenv("DEBUG") == "true"
}

// Compliant: Simplified boolean logic
func checkPermissions(user User) bool {
    if user.Role == "admin" {
        return true
    }

    return user.HasPermission("read")
}

// Compliant: Meaningful conditional logic
func validateInput(input string) error {
    if len(input) == 0 {
        return errors.New("input cannot be empty")
    }

    if len(input) > 1000 {
        return errors.New("input too long")
    }

    if !isValidFormat(input) {
        return errors.New("invalid input format")
    }

    log.Println("Input validation passed")
    return nil
}

func isValidFormat(input string) bool {
    // Actual validation logic
    matched, _ := regexp.MatchString(`^[a-zA-Z0-9_]+$`, input)
    return matched
}

// Compliant: Production-ready API handler
func apiHandler(w http.ResponseWriter, r *http.Request) {
    logger := log.WithFields(log.Fields{
        "method": r.Method,
        "path":   r.URL.Path,
    })

    logger.Info("Request received")

    response, err := processRequest(r)
    if err != nil {
        logger.WithError(err).Error("Request processing failed")
        http.Error(w, "Internal Server Error", http.StatusInternalServerError)
        return
    }

    w.Header().Set("Content-Type", "application/json")
    if err := json.NewEncoder(w).Encode(response); err != nil {
        logger.WithError(err).Error("Response encoding failed")
    }
}

